-- ----------------------------
-- Table structure for study_progress
-- ----------------------------
DROP TABLE IF EXISTS `study_progress`;
CREATE TABLE `study_progress`  (
  `id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '进度ID',
  `user_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '用户ID',
  `resource_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '资源ID',
  `progress` int NULL DEFAULT 0 COMMENT '学习进度（0-100）',
  `is_favorite` tinyint(1) NULL DEFAULT 0 COMMENT '是否收藏',
  `last_study_at` timestamp NULL DEFAULT NULL COMMENT '最后学习时间',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `study_duration` int NULL DEFAULT 0 COMMENT '学习时长（秒）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_resource`(`user_id` ASC, `resource_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_resource_id`(`resource_id` ASC) USING BTREE,
  CONSTRAINT `study_progress_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `study_progress_ibfk_2` FOREIGN KEY (`resource_id`) REFERENCES `study_resources` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '学习进度表' ROW_FORMAT = Dynamic;

