INSERT INTO `study_resources` VALUES ('294ddb9d28e01af42fe65c58d27017b8', '电视文献片《周恩来》', '专题学习', NULL, 0, '12 集文献片，中央文献研究室与央视联合摄制，以珍贵史料结合宏观叙事与细节写真，展现周恩来作为开国总理 26 年的勤政为民与伟大一生。', 0, 'https://www.dswxyjy.org.cn/NMediaFile/2019/0815/MAIN201908151508261311543831748.jpg', NULL, '2', '2026-04-13 18:26:15', '2026-04-13 18:26:15');
