INSERT INTO `study_resources` VALUES ('44846d19de80b2c6ac9b4d12ef75f22e', '7', '党史学习', NULL, 0, '11', 1, 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=study%20resource%20placeholder&image_size=square', NULL, NULL, '2026-03-30 21:26:17', '2026-03-30 21:26:17');
INSERT INTO `study_resources` VALUES ('4e955e34a238b65ec32cd40cc5458f4b', '守正创新再出发\n曲青山：习近平文化思想的里程碑意义（下集）', '党史学习', NULL, 0, '举旗定向、正本清源，守正创新、开拓进取。   \n\n党的十八大以来，党的宣传思想文化事业取得历史性成就，发生历史性变革。   \n\n党的二十届三中全会，再一次吹响了奋进号角。   \n\n深入学习宣传贯彻习近平文化思想，勇担新时代的文化使命', 14, 'https://www.dswxyjy.org.cn/NMediaFile/2025/0421/MAIN1745229254495U28CIKHK7J.jpg', 'https://mr.people.cn/appstatic/pcmp/20250421/0b35a7738674246875af39d8f2bc73c6arctrans.mp4', NULL, '2026-03-23 13:26:30', '2026-03-23 13:26:30');
